t.t:
.faq-search-wrap { position: relative; margin-bottom: 20px; }
.faq-search-wrap input { width: 100%; max-width: 520px; padding: 10px 14px 10px 40px; border: 1px solid var(--border); border-radius: 8px; font-size: 14px; font-family: inherit; background: var(--bg-card); outline: none; transition: border 0.15s; }
.faq-search-wrap input:focus { border-color: var(--action); box-shadow: 0 0 0 3px rgba(29,158,117,0.10); }
.faq-search-icon { position: absolute; left: 13px; top: 50%; transform: translateY(-50%); color: var(--text-muted); }
.faq-item { background: var(--bg-card); border: 1px solid var(--border); border-radius: 10px; margin-bottom: 10px; overflow: hidden; transition: opacity 0.2s; }
.faq-item.hidden { opacity: 0.15; pointer-events: none; height: 0; margin: 0; border: none; }
.faq-question { display: flex; align-items: center; gap: 12px; padding: 15px 18px; cursor: pointer; user-select: none; }
.faq-question:hover { background: #FAFBFD; }
.faq-q-text { font-size: 14px; font-weight: 500; flex: 1; }
.faq-chevron { color: var(--primary); font-size: 12px; transition: transform 0.2s; flex-shrink: 0; }
.faq-item.open .faq-chevron { transform: rotate(180deg); }
.faq-answer { display: none; padding: 0 18px 16px 18px; font-size: 13.5px; color: var(--text-muted); line-height: 1.65; border-top: 1px solid var(--border); padding-top: 14px; }
.faq-item.open .faq-answer { display: block; }
.filter-pills { display: flex; gap: 6px; flex-wrap: wrap; margin-bottom: 20px; }
.filter-pill { padding: 5px 14px; border-radius: 20px; font-size: 12.5px; border: 1px solid var(--border); background: var(--bg-card); color: var(--text-muted); cursor: pointer; transition: all 0.15s; font-family: inherit; }
.filter-pill.active, .filter-pill:hover { background: var(--primary); color: #fff; border-color: var(--primary); }

t.script:
let activeFaqFilter = 'todos';
function setFaqFilter(el, cat) { 
    document.querySelectorAll('.filter-pill').forEach(p => p.classList.remove('active')); 
    el.classList.add('active'); 
    activeFaqFilter = cat; 
    filterFaq(); 
}
function filterFaq() { 
    const q = document.getElementById('faq-search').value.toLowerCase(); 
    document.querySelectorAll('.faq-item').forEach(item => { 
        const matchCat = activeFaqFilter === 'todos' || item.dataset.cat === activeFaqFilter; 
        const matchQ = !q || item.dataset.search.includes(q) || item.querySelector('.faq-q-text').textContent.toLowerCase().includes(q); 
        item.classList.toggle('hidden', !(matchCat && matchQ)); 
    }); 
}
function toggleFaq(el) { 
    const item = el.closest('.faq-item'); 
    item.classList.toggle('open'); 
}
